typealias Handler = (Request) -> Response

class Router {
    private val routes = mutableMapOf<Pair<String, String>, Handler>()

    fun get(path: String, handler: Handler) { routes["GET" to path] = handler }
    fun post(path: String, handler: Handler) { routes["POST" to path] = handler }

    fun handle(req: Request): Response {
        val handler = routes[req.method to req.path]
        return handler?.invoke(req) ?: Response(404, "not found")
    }
}

fun main() {
    val router = Router()
    val articles = mutableListOf<String>()

    router.get("/articles") { Response(200, articles.joinToString(",")) }
    router.post("/articles") {
        articles.add("item-${articles.size + 1}")
        Response(201, "created")
    }

    println(router.handle(Request("GET", "/articles")))
    println(router.handle(Request("POST", "/articles")))
    println(router.handle(Request("GET", "/articles")))
}

typealias Handler = (Request) -> Response

class Router {
    private val routes = mutableMapOf<Pair<String, String>, Handler>()

    fun get(path: String, handler: Handler) { routes["GET" to path] = handler }

    fun handle(req: Request): Response {
        routes[req.method to req.path]?.let { return it(req) }
        if (req.method == "GET" && req.path.startsWith("/articles/")) {
            val id = req.path.removePrefix("/articles/")
            return Response(200, "article-$id")
        }
        return Response(404, "not found")
    }
}

