class QueryBuilder {
    private var table: String = ""
    private val columns = mutableListOf<String>()
    private var where: String? = null

    fun select(vararg cols: String) = apply { columns.addAll(cols) }
    fun from(t: String) = apply { table = t }
    fun where(clause: String) = apply { where = clause }

    fun build(): Query = Query(table, columns.ifEmpty { listOf("*") }, where)
}

@DslMarker
annotation class QueryDsl

@QueryDsl
class QueryDslBuilder {
    private val inner = QueryBuilder()
    fun select(vararg cols: String) = inner.select(*cols)
    fun from(table: String) = inner.from(table)
    fun where(clause: String) = inner.where(clause)
    fun build() = inner.build()
}

fun query(block: QueryDslBuilder.() -> Unit): Query {
    val b = QueryDslBuilder()
    b.block()
    return b.build()
}

fun Query.toSql(): String {
    val cols = columns.joinToString(", ")
    val base = "SELECT $cols FROM $table"
    return if (where != null) "$base WHERE $where" else base
}

fun main() {
    val q = query {
        select("id", "name")
        from("users")
        where("active = 1")
    }
    println(q.toSql())
}

import kotlinx.coroutines.delay
import kotlinx.coroutines.sync.Mutex
import kotlinx.coroutines.sync.withLock

class RateLimiter(private val maxPermits: Int, private val refillMs: Long) {
    private var permits = maxPermits
    private val mutex = Mutex()

    suspend fun acquire() = mutex.withLock {
        while (permits == 0) {
            mutex.unlock()
            delay(refillMs)
            mutex.lock()
            permits = maxPermits
        }
        permits--
    }
}

